    func decrypt(_ ciphertext: Data) throws -> Data
}

public final class AESGCMCryptoProvider: CryptoProvider {
    private let keyTag: String
    private let keychain: KeychainStore

    public init(keyTag: String = "com.example.banking.ledger.aesgcm.key", keychain: KeychainStore = .shared) {
        self.keyTag = keyTag
        self.keychain = keychain
    }

    private func loadOrCreateKey() throws -> SymmetricKey {
        if let existing = try keychain.readKey(tag: keyTag) {
            return SymmetricKey(data: existing)
        }
        var bytes = [UInt8](repeating: 0, count: 32)
        let status = SecRandomCopyBytes(kSecRandomDefault, bytes.count, &bytes)
        guard status == errSecSuccess else { throw BankingError.cryptoFailure }
        let data = Data(bytes)
        try keychain.upsertKey(tag: keyTag, data: data)
        return SymmetricKey(data: data)
    }

    public func encrypt(_ plaintext: Data) throws -> Data {
        let key = try loadOrCreateKey()
        let sealed = try AES.GCM.seal(plaintext, using: key)
        guard let combined = sealed.combined else { throw BankingError.cryptoFailure }
        return combined
    }

    public func decrypt(_ ciphertext: Data) throws -> Data {
        let key = try loadOrCreateKey()
        let box = try AES.GCM.SealedBox(combined: ciphertext)
        return try AES.GCM.open(box, using: key)
    }
}

