public final class BankingEngine: @unchecked Sendable {
    private let store: LedgerStore
    private let queue = DispatchQueue(label: "com.example.banking.engine.serial", qos: .userInitiated)

    public init(store: LedgerStore) {
        self.store = store
    }

    public func createAccount(displayName: String, currencyCode: String, openingBalanceMinor: Int64 = 0) async throws -> Account {
