            queue.async {
                do {
                    var snapshot = try self.store.load()
                    var account = Account(displayName: displayName, currencyCode: currencyCode, balanceMinor: openingBalanceMinor, updatedAt: Date())
                    snapshot.accounts[account.id] = account
                    try self.store.save(snapshot)
                    cont.resume(returning: account)
                } catch {
                    cont.resume(throwing: error)
                }
            }
        }
    }

    public func getAccounts() async throws -> [Account] {
        try await withCheckedThrowingContinuation { cont in
            queue.async {
                do {
                    let snapshot = try self.store.load()
                    let accounts = snapshot.accounts.values.sorted { $0.displayName.localizedCaseInsensitiveCompare($1.displayName) == .orderedAscending }
                    cont.resume(returning: accounts)
                } catch {
                    cont.resume(throwing: error)
                }
            }
        }
    }

    public func getAccount(id: UUID) async throws -> Account {
        try await withCheckedThrowingContinuation { cont in
            queue.async {
                do {
                    let snapshot = try self.store.load()
                    guard let account = snapshot.accounts[id] else { throw BankingError.accountNotFound }
                    cont.resume(returning: account)
                } catch {
                    cont.resume(throwing: error)
                }
            }
        }
    }

    public func getTransactions(accountId: UUID? = nil) async throws -> [Transaction] {
        try await withCheckedThrowingContinuation { cont in
            queue.async {
                do {
                    let snapshot = try self.store.load()
                    let txs: [Transaction]
                    if let accountId {
                        txs = snapshot.transactions.filter { $0.accountId == accountId }.sorted { $0.createdAt > $1.createdAt }
                    } else {
                        txs = snapshot.transactions.sorted { $0.createdAt > $1.createdAt }
                    }
                    cont.resume(returning: txs)
                } catch {
                    cont.resume(throwing: error)
                }
            }
        }
    }

    public func process(_ request: TransactionRequest) async throws -> Transaction {
        try await withCheckedThrowingContinuation { cont in
            queue.async {
                do {
                    guard request.amountMinor > 0 else { throw BankingError.invalidAmount }

                    var snapshot = try self.store.load()

                    if snapshot.processedIdempotencyKeys.contains(request.idempotencyKey) {
                        throw BankingError.duplicateTransaction
                    }

                    guard var account = snapshot.accounts[request.accountId] else { throw BankingError.accountNotFound }
                    guard account.currencyCode.uppercased() == request.currencyCode.uppercased() else { throw BankingError.currencyMismatch }

                    let delta: Int64
                    switch request.type {
                    case .credit:
                        delta = request.amountMinor
                    case .debit:
                        delta = -request.amountMinor
                        if account.balanceMinor + delta < 0 { throw BankingError.insufficientFunds }
                    }

                    account.balanceMinor += delta
                    account.updatedAt = Date()
                    snapshot.accounts[account.id] = account

                    let tx = Transaction(
                        accountId: request.accountId,
                        type: request.type,
                        amountMinor: request.amountMinor,
                        currencyCode: request.currencyCode.uppercased(),
                        memo: request.memo,
                        createdAt: Date(),
                        idempotencyKey: request.idempotencyKey
                    )

                    snapshot.transactions.append(tx)
                    snapshot.processedIdempotencyKeys.insert(request.idempotencyKey)

                    try self.store.save(snapshot)
                    cont.resume(returning: tx)
                } catch {
                    cont.resume(throwing: error)
                }
            }
        }
    }

    public func transfer(
        from sourceAccountId: UUID,
        to destinationAccountId: UUID,
        amountMinor: Int64,
        currencyCode: String,
        memo: String? = nil,
        idempotencyKey: String
    ) async throws -> (debit: Transaction, credit: Transaction) {
        try await withCheckedThrowingContinuation { cont in
            queue.async {
                do {
                    guard amountMinor > 0 else { throw BankingError.invalidAmount }

                    var snapshot = try self.store.load()

                    if snapshot.processedIdempotencyKeys.contains(idempotencyKey) {
                        throw BankingError.duplicateTransaction
                    }

                    guard var source = snapshot.accounts[sourceAccountId] else { throw BankingError.accountNotFound }
                    guard var dest = snapshot.accounts[destinationAccountId] else { throw BankingError.accountNotFound }

                    let cc = currencyCode.uppercased()
                    guard source.currencyCode.uppercased() == cc, dest.currencyCode.uppercased() == cc else { throw BankingError.currencyMismatch }

                    if source.balanceMinor - amountMinor < 0 { throw BankingError.insufficientFunds }

                    source.balanceMinor -= amountMinor
                    source.updatedAt = Date()
                    dest.balanceMinor += amountMinor
                    dest.updatedAt = Date()

                    snapshot.accounts[source.id] = source
                    snapshot.accounts[dest.id] = dest

                    let debitTx = Transaction(
                        accountId: source.id,
                        type: .debit,
                        amountMinor: amountMinor,
                        currencyCode: cc,
                        memo: memo,
                        createdAt: Date(),
                        idempotencyKey: idempotencyKey + ":debit"
                    )
                    let creditTx = Transaction(
                        accountId: dest.id,
                        type: .credit,
                        amountMinor: amountMinor,
                        currencyCode: cc,
                        memo: memo,
                        createdAt: Date(),
                        idempotencyKey: idempotencyKey + ":credit"
                    )

                    snapshot.transactions.append(debitTx)
                    snapshot.transactions.append(creditTx)
                    snapshot.processedIdempotencyKeys.insert(idempotencyKey)

                    try self.store.save(snapshot)
                    cont.resume(returning: (debitTx, creditTx))
                } catch {
                    cont.resume(throwing: error)
                }
            }
        }
    }

    public func resetAllData() async throws {
        try await withCheckedThrowingContinuation { cont in
            queue.async {
                do {
                    try self.store.reset()
                    cont.resume()
                } catch {
                    cont.resume(throwing: error)
                }
            }
        }
    }
}

// MARK: - Formatting

public struct MoneyFormatter {
    public init() {}

    public func string(amountMinor: Int64, currencyCode: String, locale: Locale = .current) -> String {
        let formatter = NumberFormatter()
        formatter.numberStyle = .currency
        formatter.currencyCode = currencyCode.uppercased()
        formatter.locale = locale

        let fractionDigits = formatter.maximumFractionDigits
        let divisor = pow(10.0, Double(fractionDigits))
        let major = Double(amountMinor) / divisor
        return formatter.string(from: NSNumber(value: major)) ?? "\(major) \(currencyCode.uppercased())"
    }
}

// MARK: - SwiftUI UI (iOS 13+)

#if canImport(SwiftUI)
import SwiftUI

@MainActor
public final class BankingViewModel: ObservableObject {
    @Published public private(set) var accounts: [Account] = []
    @Published public private(set) var selectedAccount: Account?
    @Published public private(set) var transactions: [Transaction] = []
    @Published public var errorMessage: String?

    private let engine: BankingEngine
    private let formatter = MoneyFormatter()

    public init(engine: BankingEngine) {
        self.engine = engine
    }

    public func load() async {
        do {
            let accounts = try await engine.getAccounts()
            self.accounts = accounts
            if selectedAccount == nil {
                self.selectedAccount = accounts.first
            } else if let sel = selectedAccount, let refreshed = accounts.first(where: { $0.id == sel.id }) {
                self.selectedAccount = refreshed
            }
            if let account = selectedAccount {
                self.transactions = try await engine.getTransactions(accountId: account.id)
            } else {
                self.transactions = []
            }
            self.errorMessage = nil
        } catch {
            self.errorMessage = (error as? LocalizedError)?.errorDescription ?? String(describing: error)
        }
    }

    public func selectAccount(_ account: Account) async {
        self.selectedAccount = account
        await load()
    }

    public func createSampleIfNeeded() async {
        do {
            let existing = try await engine.getAccounts()
            if !existing.isEmpty { return }
            _ = try await engine.createAccount(displayName: "Checking", currencyCode: "USD", openingBalanceMinor: 125_00)
            _ = try await engine.createAccount(displayName: "Savings", currencyCode: "USD", openingBalanceMinor: 2500_00)
            await load()
        } catch {
            self.errorMessage = (error as? LocalizedError)?.errorDescription ?? String(describing: error)
        }
    }

    public func postTransaction(type: TransactionType, amountMinor: Int64, memo: String? = nil) async {
        guard let account = selectedAccount else { return }
        do {
            let req = TransactionRequest(
                accountId: account.id,
                type: type,
                amountMinor: amountMinor,
                currencyCode: account.currencyCode,
                memo: memo,
                idempotencyKey: UUID().uuidString
            )
            _ = try await engine.process(req)
            await load()
        } catch {
            self.errorMessage = (error as? LocalizedError)?.errorDescription ?? String(describing: error)
        }
    }

    public func balanceString(for account: Account) -> String {
        formatter.string(amountMinor: account.balanceMinor, currencyCode: account.currencyCode)
    }

    public func transactionAmountString(_ tx: Transaction) -> String {
        let signedMinor: Int64 = (tx.type == .debit) ? -tx.amountMinor : tx.amountMinor
        return formatter.string(amountMinor: signedMinor, currencyCode: tx.currencyCode)
    }
}

public struct BankingDashboardView: View {
    @StateObject private var vm: BankingViewModel
    @State private var amountText: String = ""
    @State private var memoText: String = ""
    @State private var txType: TransactionType = .debit

    public init(engine: BankingEngine) {
        _vm = StateObject(wrappedValue: BankingViewModel(engine: engine))
    }

    public var body: some View {
        NavigationView {
            VStack(spacing: 12) {
                if let msg = vm.errorMessage {
                    Text(msg)
                        .foregroundColor(.red)
                        .font(.footnote)
                        .padding(.horizontal)
                }

                accountPicker

                if let account = vm.selectedAccount {
                    VStack(alignment: .leading, spacing: 6) {
                        Text(account.displayName)
                            .font(.headline)
                        Text("Balance: \(vm.balanceString(for: account))")
                            .font(.title3)
                            .bold()
                    }
                    .frame(maxWidth: .infinity, alignment: .leading)
                    .padding(.horizontal)
                }

                transactionComposer

                Divider().padding(.horizontal)

                List {
                    ForEach(vm.transactions) { tx in
                        VStack(alignment: .leading, spacing: 4) {
                            HStack {
                                Text(tx.type.rawValue.capitalized)
                                    .font(.subheadline)
                                    .foregroundColor(tx.type == .debit ? .orange : .green)
                                Spacer()
                                Text(vm.transactionAmountString(tx))
                                    .font(.subheadline)
                                    .bold()
                            }
                            if let memo = tx.memo, !memo.isEmpty {
                                Text(memo).font(.footnote).foregroundColor(.secondary)
                            }
                            Text(tx.createdAt, style: .date)
                                .font(.caption)
                                .foregroundColor(.secondary)
                        }
                        .padding(.vertical, 4)
                    }
                }
                .listStyle(.plain)
            }
            .navigationTitle("Accounts")
            .task {
                await vm.createSampleIfNeeded()
                await vm.load()
            }
            .refreshable {
                await vm.load()
            }
        }
        .navigationViewStyle(.stack)
    }

    private var accountPicker: some View {
        ScrollView(.horizontal, showsIndicators: false) {
            HStack(spacing: 10) {
                ForEach(vm.accounts) { account in
                    Button {
                        Task { await vm.selectAccount(account) }
                    } label: {
                        VStack(alignment: .leading, spacing: 4) {
                            Text(account.displayName)
                                .font(.subheadline)
                                .bold()
                            Text(vm.balanceString(for: account))
                                .font(.caption)
                                .foregroundColor(.secondary)
                        }
                        .padding(10)
                        .background(vm.selectedAccount?.id == account.id ? Color.accentColor.opacity(0.15) : Color.secondary.opacity(0.08))
                        .cornerRadius(10)
                    }
                    .buttonStyle(.plain)
                }
            }
            .padding(.horizontal)
        }
    }

    private var transactionComposer: some View {
        VStack(spacing: 10) {
            HStack(spacing: 10) {
                Picker("Type", selection: $txType) {
                    Text("Debit").tag(TransactionType.debit)
                    Text("Credit").tag(TransactionType.credit)
                }
                .pickerStyle(.segmented)
            }
            .padding(.horizontal)

            HStack(spacing: 10) {
                TextField("Amount (e.g. 12.34)", text: $amountText)
                    .keyboardType(.decimalPad)
                    .textFieldStyle(.roundedBorder)

                Button("Post") {
                    Task {
                        guard let account = vm.selectedAccount else { return }
                        let minor = Self.parseMinorUnits(amountText, currencyCode: account.currencyCode)
                        await vm.postTransaction(type: txType, amountMinor: minor, memo: memoText.isEmpty ? nil : memoText)
                        amountText = ""
                        memoText = ""
                    }
                }
                .buttonStyle(.borderedProminent)
                .disabled(vm.selectedAccount == nil)
            }
            .padding(.horizontal)

            TextField("Memo (optional)", text: $memoText)
                .textFieldStyle(.roundedBorder)
                .padding(.horizontal)
        }
    }

    private static func parseMinorUnits(_ text: String, currencyCode: String) -> Int64 {
        let trimmed = text.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty else { return 0 }

        let formatter = NumberFormatter()
        formatter.numberStyle = .decimal
        formatter.locale = .current

        if let number = formatter.number(from: trimmed) {
            let currencyFormatter = NumberFormatter()
            currencyFormatter.numberStyle = .currency
            currencyFormatter.currencyCode = currencyCode.uppercased()
            currencyFormatter.locale = .current
            let fractionDigits = currencyFormatter.maximumFractionDigits
            let multiplier = pow(10.0, Double(fractionDigits))
            let minor = (number.doubleValue * multiplier).rounded()
            return Int64(minor)
        }

        let normalized = trimmed.replacingOccurrences(of: ",", with: ".")
        if let d = Double(normalized) {
            let currencyFormatter = NumberFormatter()
            currencyFormatter.numberStyle = .currency
            currencyFormatter.currencyCode = currencyCode.uppercased()
            currencyFormatter.locale = .current
            let fractionDigits = currencyFormatter.maximumFractionDigits
            let multiplier = pow(10.0, Double(fractionDigits))
            return Int64((d * multiplier).rounded())
        }

        return 0
    }
}
